function describe(prefix) { return prefix + ' ' + this.role; }
const obj = { role: 'admin' };
console.log(describe.call(obj, 'User:'));   // 'User: admin'
console.log(describe.apply(obj, ['Role:'])); // 'Role: admin'
const boundDescribe = describe.bind(obj, 'Hi');
setTimeout(() => console.log(boundDescribe()), 10); // 'Hi admin'

